import{_ as e,o as d,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt3306.jpg",n="/images/lekt3307.jpg",l="/images/lekt3305.jpg",o="/images/lekt3304.jpg",s="/images/lekt3303.jpg",u="/images/lekt3302.jpg",p="/images/lekt3308.jpg",P=JSON.parse('{"title":"Lektion 33","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion33.md","filePath":"lektionen/lektion33.md"}'),h={name:"lektionen/lektion33.md"};function b(m,t,k,c,g,f){return d(),r("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-33" tabindex="-1">Lektion 33 <a class="header-anchor" href="#lektion-33" aria-label="Permalink to &quot;Lektion 33&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>33.1. Die Reduplikation (अभ्यास m.) <ul><li>33.1.1. Der Reduplikationskonsonant</li></ul></li><li>33.2. Die dritte Präsensklasse (जुहोत्यादि = &quot;जुहोति u.s.w.&quot;) <ul><li>33.2.1. Der Reduplikationsvokal der 3. Präsensklasse</li></ul></li><li>33.3. Zum Ablaut von ā</li><li>33.4. Wurzeln auf -ā der dritten Präsensklasse <ul><li>33.4.1. Die Wurzeln दा und धा</li></ul></li><li>33.5. Das Partizip Präsens Parasmaipada der Wurzeln der 3. Präsensklasse</li><li>33.6. Wortliste</li><li>33.7. Übung</li></ul><h2 id="_33-1-die-reduplikation-अभ्यास-m" tabindex="-1">33.1. Die Reduplikation (अभ्यास m.) <a class="header-anchor" href="#_33-1-die-reduplikation-अभ्यास-m" aria-label="Permalink to &quot;33.1. Die Reduplikation (अभ्यास m.)&quot;">​</a></h2><ul><li>Die dritte Präsensklasse</li><li>(sowie einige Verben anderer Präsensklassen),</li><li>das Perfekt,</li><li>der reduplizierte Aorist,</li><li>das Frequentativum und</li><li>das Desiderativum</li></ul><p>werden mittels Reduplikation gebildet. Der Teil einer reduplizierten Form, der vor die Wurzel gesetzt wird, heißt Reduplikationssilbe.</p><p>Die Reduplikationssilbe besteht aus (einem Konsonanten und) einem Vokal.</p><h3 id="_33-1-1-der-reduplikationskonsonant" tabindex="-1">33.1.1. Der Reduplikationskonsonant <a class="header-anchor" href="#_33-1-1-der-reduplikationskonsonant" aria-label="Permalink to &quot;33.1.1. Der Reduplikationskonsonant&quot;">​</a></h3><p>1. Gewöhnlich:</p><p>Wiederholung des ersten Konsonanten der Wurzel</p><p>Beispiele:</p><blockquote><p>दा 3 &quot;geben&quot;</p><blockquote><p>3.sg.P.Ind.Präs. ददाति</p></blockquote><p>पॄ 3 &quot;füllen&quot;</p><blockquote><p>3.sg.P.Ind.Präs. पिपर्ति</p></blockquote><p>मा 3Ā &quot;messen&quot;</p><blockquote><p>3.sg.Ā.Ind.Präs. मिमीते</p></blockquote></blockquote><p>2. Ein aspirierter Anfangskonsonant einer Wurzel wird durch den entsprechenden nicht-aspirierten Konsonanten redupliziert.</p><p>Beispiele:</p><blockquote><p>धा 3 &quot;setzen&quot;</p><blockquote><p>3.sg.P.Ind.Präs. दधाति</p></blockquote><p>भी  3 &quot;fürchten&quot;</p><blockquote><p>3.sg.P.Ind.Präs. बिभेति</p></blockquote></blockquote><p>3. Ein Guttural wird durch den ihm entsprechenden nicht-aspirierten Palatal redupliziert:</p><blockquote><p>क्, ख् durch च्<br> ग्, घ् durch ज्</p></blockquote><p>ह् wird immer durch ज् redupliziert.</p><p>Beispiele:</p><blockquote><p>हु 3 &quot;(zum Opfer) ins Feuer gießen&quot;</p><blockquote><p>3.sg.P.Ind.Präs. जुहोति</p></blockquote></blockquote><p>4. Beginnt eine Wurzel mit mehreren Konsonanten, so wird nur der erste (gegebenenfalls unter Anwendung von Regel 2 bzw. 3) wiederholt.</p><p>5. Beginnt eine Wurzel mit einer Konsonantengruppe Zischlaut + tonloser Konsonant, so wird nicht der Zischlaut, sondern der darauf folgende tonlose Konsonant gemäß obigen Regeln redupliziert.</p><p>Beispiel:</p><blockquote><p>स्था 1 &quot;stehen&quot;</p><blockquote><p>3.sg.P.Ind.Präs. तिष्ठति</p></blockquote></blockquote><h2 id="_33-2-die-dritte-prasensklasse-जुहोत्यादि-जुहोति-u-s-w" tabindex="-1">33.2. Die dritte Präsensklasse (जुहोत्यादि = &quot;जुहोति u.s.w.&quot;) <a class="header-anchor" href="#_33-2-die-dritte-prasensklasse-जुहोत्यादि-जुहोति-u-s-w" aria-label="Permalink to &quot;33.2. Die dritte Präsensklasse (जुहोत्यादि = &quot;जुहोति u.s.w.&quot;)&quot;">​</a></h2><p>Bildung:</p><p>starker Stamm:</p><p>reduplizierte hochstufige Wurzel + Endung</p><p>schwacher Stamm:</p><p>reduplizierte tiefstufige Wurzel + Endung</p><p>Für den Reduplikationskonsonanten gelten die oben gegebenen Regeln</p><h3 id="_33-2-1-der-reduplikationsvokal-der-3-prasensklasse" tabindex="-1">33.2.1. Der Reduplikationsvokal der 3. Präsensklasse <a class="header-anchor" href="#_33-2-1-der-reduplikationsvokal-der-3-prasensklasse" aria-label="Permalink to &quot;33.2.1. Der Reduplikationsvokal der 3. Präsensklasse&quot;">​</a></h3><ul><li>Der regelmäßige Reduplikationsvokal ist -i-</li><li>u-haltige Wurzeln reduplizieren mit -u-</li><li>die Wurzeln दा, धा, हा mit -a-</li></ul><p>Beispiele:</p><blockquote><p>हु 3P &quot;(zum Opfer) ins Feuer gießen&quot;</p><blockquote><ul><li>starker Stamm: जुहो</li><li>schwacher Stamm: जुहु</li></ul></blockquote><table tabindex="0"><thead><tr><th></th><th>3.sg.P</th><th>3.pl.P</th><th>3.sg.Ā</th><th>3.pl.Ā</th></tr></thead><tbody><tr><td>Indikativ Präsens</td><td>जुहोति</td><td>जुह्वति</td><td></td><td></td></tr><tr><td>juhu + ati</td><td>&lt;जुहुते&gt;</td><td>&lt;जुह्वते&gt;</td><td></td><td></td></tr><tr><td>juhu + ate</td><td></td><td></td><td></td><td></td></tr><tr><td>Imperfekt</td><td>अजुहोत्</td><td></td><td></td><td></td></tr><tr><td>a-juho-t</td><td>जुहवुर्</td><td></td><td></td><td></td></tr><tr><td>a-juho + ur</td><td>&lt;अजुहुत&gt;</td><td>&lt;अजुह्वत&gt;</td><td></td><td></td></tr><tr><td>a-juhu + ata</td><td></td><td></td><td></td><td></td></tr><tr><td>Optativ</td><td>जुहुयात्</td><td></td><td></td><td></td></tr><tr><td>juhu-yā-t</td><td>जुहुयुर्</td><td></td><td></td><td></td></tr><tr><td>juhu-y-ur</td><td>&lt;जुह्वीत&gt;</td><td></td><td></td><td></td></tr><tr><td>juhu + ī-ta</td><td>&lt;जुह्वीरन्&gt;</td><td></td><td></td><td></td></tr><tr><td>juhu + ī-ran</td><td></td><td></td><td></td><td></td></tr></tbody></table></blockquote><h2 id="_33-3-zum-ablaut-von-a" tabindex="-1">33.3. Zum Ablaut von ā <a class="header-anchor" href="#_33-3-zum-ablaut-von-a" aria-label="Permalink to &quot;33.3. Zum Ablaut von ā&quot;">​</a></h2><p>ā kann</p><ul><li>einerseits Dehnstufe einer der Ablautreihen mit -a- sein</li><li>andrerseits Hochstufe in einer Ablautreihe der ā-Gruppe sein</li></ul><p>Die beiden wichtigsten Ablautreihen der ā-Gruppe sind:</p><p>A.</p><ul><li>Tiefstufe <ul><li>vor Konsonant: -i-<br> z.B. धा PPP: हित (hi-ta)</li><li>vor Vokal: Ø<br> z.B. धा 3.pl.P.Ind.Präs. दधति (dadh-ati)</li></ul></li><li>Hochstufe: -ā-<br> z.B. धा 3.sg.P.Ind.Präs. दधाति</li></ul><p>Hierher gehört z.B. auch:</p><blockquote><p>स्था् 1</p><blockquote><p>PPP स्थित (sthi-ta)<br> 3.sg.P.Fut. स्थास्यति (sthā-sya-ti)</p></blockquote></blockquote><p>B.</p><ul><li>Tiefstufe: -ī-<br> z.B. पा 1: PPP पीत (pī-ta)</li><li>Hochstufe: -ā-<br> z.B. पा 1: Inf. पातुम्</li></ul><h2 id="_33-4-wurzeln-auf-a-der-dritten-prasensklasse" tabindex="-1">33.4. Wurzeln auf -ā der dritten Präsensklasse <a class="header-anchor" href="#_33-4-wurzeln-auf-a-der-dritten-prasensklasse" aria-label="Permalink to &quot;33.4. Wurzeln auf -ā der dritten Präsensklasse&quot;">​</a></h2><p>Wurzeln auf -ā (außer दा und धा) lauten im schwachen Stamm gewöhnlich auf -ī- ab (siehe dazu Thumb-Hauschild Bd. 1,1 S. 271. Vermutlich wirkte dabei die oben  genannte Ablautreihe B als Vorbild, obwohl diese Wurzeln sonst nach Reihe A ablauten), vor vokalischen Endungen verschwindet der Wurzelvokal vollständig (siehe Ablautreihe A).</p><p>Beispiele:</p><blockquote><p>मा 3Ā &quot;messen&quot;</p><table tabindex="0"><thead><tr><th></th><th>3.sg.Ā</th><th>3.pl.Ā</th></tr></thead><tbody><tr><td>Indikativ Präsens</td><td>मिमीते</td><td></td></tr><tr><td>mimī-te</td><td>मिमते</td><td></td></tr><tr><td>mim-ate</td><td></td><td></td></tr><tr><td>Imperfekt</td><td>अमिमीत</td><td>अमिमत</td></tr><tr><td>Optativ</td><td>मिमीत</td><td></td></tr><tr><td>mim-ī-ta !</td><td>मिमीरन्</td><td></td></tr><tr><td>mim-ī-ran</td><td></td><td></td></tr></tbody></table><p>हा 3P &quot;verlassen&quot;</p><table tabindex="0"><thead><tr><th></th><th>3.sg.P</th><th>3.pl.P</th></tr></thead><tbody><tr><td>Indikativ Präsens</td><td>जहाति</td><td>जहति</td></tr><tr><td>jah-ati</td><td></td><td></td></tr><tr><td>Imperfekt</td><td>अजहात्</td><td>अजहुर्</td></tr><tr><td>Optativ</td><td>जह्यात्</td><td></td></tr><tr><td>jah-yā-t</td><td></td><td></td></tr><tr><td>Die Wurzel हा hat vor dem Optativ-yā/y die gleiche Form wie vor Vokalen!</td><td>जह्युर्</td><td></td></tr><tr><td>jah-y-ur</td><td></td><td></td></tr></tbody></table></blockquote><h3 id="_33-4-1-die-wurzeln-दा-und-धा" tabindex="-1">33.4.1. Die Wurzeln दा und धा <a class="header-anchor" href="#_33-4-1-die-wurzeln-दा-und-धा" aria-label="Permalink to &quot;33.4.1. Die Wurzeln दा und धा&quot;">​</a></h3><p>Die Wurzeln दा und धा reduplizieren mit dem Vokal -a- und verlieren im schwachen Stamm den Wurzelvokal.</p><p>Beachten Sie bei धा das hauchdissimilationsgesetz!</p><p>धा 3U &quot;setzen, festsetzen, zuteilen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>3.sg.P</th><th>3.pl.P</th><th>3.sg.Ā</th><th>3.pl.Ā</th></tr></thead><tbody><tr><td>Indikativ Präsens</td><td>दधाति</td><td>दधति</td><td></td><td></td></tr><tr><td>dadh-ati</td><td>धत्ते</td><td></td><td></td><td></td></tr><tr><td>dadh-te</td><td></td><td></td><td></td><td></td></tr><tr><td>(Erklärung: Thumb-Hauschild 1,1 S. 302f.)</td><td>दधते</td><td></td><td></td><td></td></tr><tr><td>dadh-ate</td><td></td><td></td><td></td><td></td></tr><tr><td>Imperfekt</td><td>अदधात्</td><td>अदधुर्</td><td>अधत्त</td><td></td></tr><tr><td>a + dadh + ta</td><td>अदधत</td><td></td><td></td><td></td></tr><tr><td>Optativ</td><td>दध्यात्</td><td></td><td></td><td></td></tr><tr><td>dadh-yā-t</td><td>दध्युर्</td><td>दधीत</td><td></td><td></td></tr><tr><td>dadh-ī-ta</td><td>दधीरन्</td><td></td><td></td><td></td></tr></tbody></table></blockquote><p>Die Formen von दा erhält man, indem man im Paradigma von धा dh durch d ersetzt. Also:</p><p>दा 3U &quot;geben&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>3.sg.P</th><th>3.pl.P</th><th>3.sg.Ā</th><th>3.pl.Ā</th></tr></thead><tbody><tr><td>Indikativ Präsens</td><td>ददाति</td><td>ददति</td><td>दत्ते</td><td>ददते</td></tr><tr><td>Imperfekt</td><td>अददात्</td><td>अददुर्</td><td>अदत्त</td><td>अददत</td></tr><tr><td>Optativ</td><td>दद्यात्</td><td>दद्युर्</td><td>ददीत</td><td>ददीरन्</td></tr></tbody></table></blockquote><h2 id="_33-5-das-partizip-prasens-parasmaipada-der-wurzeln-der-3-prasensklasse" tabindex="-1">33.5. Das Partizip Präsens Parasmaipada der Wurzeln der 3. Präsensklasse <a class="header-anchor" href="#_33-5-das-partizip-prasens-parasmaipada-der-wurzeln-der-3-prasensklasse" aria-label="Permalink to &quot;33.5. Das Partizip Präsens Parasmaipada der Wurzeln der 3. Präsensklasse&quot;">​</a></h2><p>Die Verben der 3. Klasse bilden alle Formen des Partizip Präsens Parasmaipada vom schwachen Stamm.</p><p>Ausnahme: Nominativ/Akkusativ Plural Neutrum kann wahlweise vom starken oder schwachen Stamm gebildet werden.</p><p>Beispiel:</p><p>दा Partizip Präsens Parasmaipada:</p><blockquote><table tabindex="0"><thead><tr><th></th><th>Maskulinum</th><th>Neutrum</th><th>Femininum</th></tr></thead><tbody><tr><td>Singular</td><td></td><td></td><td></td></tr><tr><td>1. Nominativ</td><td>ददत्</td><td></td><td></td></tr><tr><td>dad-at + s</td><td>ददत्</td><td></td><td></td></tr><tr><td>dad-at-Ø</td><td>ददती</td><td></td><td></td></tr><tr><td>2. Akkusativ</td><td>ददतम्</td><td></td><td></td></tr><tr><td>dad-at-am</td><td>ददत्</td><td></td><td></td></tr><tr><td>Plural</td><td></td><td></td><td></td></tr><tr><td>1. Nominativ</td><td>ददतस्</td><td>ददति</td><td></td></tr><tr><td>das-at-i</td><td></td><td></td><td></td></tr><tr><td>ददन्ति</td><td></td><td></td><td></td></tr><tr><td>dad-ant-i</td><td></td><td></td><td></td></tr><tr><td>2. Akkusativ</td><td>ददतस्</td><td>ददति</td><td></td></tr><tr><td>ददन्ति</td><td></td><td></td><td></td></tr></tbody></table></blockquote><p>Ähnlich जुह्वत् (juhu-at + s)</p><h2 id="_33-6-wortliste" tabindex="-1">33.6. Wortliste <a class="header-anchor" href="#_33-6-wortliste" aria-label="Permalink to &quot;33.6. Wortliste&quot;">​</a></h2><p>दा 3U ददाति : geben</p><blockquote><p>Fut. दास्यति<br> Pass. दीयते<br> Kaus. दापयति<br> PPP दत्त<br> Inf. दातुम्</p><p>davon:</p><p>दान n.: Geben, Gabe, Freigebigkeit</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: दानम्</p><blockquote><p>&quot;On August 20th, 2005 in Chennai, India my soon to be in-laws gave us a formal Indian engagement party. It looks like it was a wedding but it wasn&#39;t, it&#39;s how they do things. Very extravagate. This event was a huge blessing for me. I have never felt so love by another family. I only wish my family could have been there but at least I have a video of the whole thing to share. My soon to be in-laws made the whole thing happen in 3 days. Everything between invitations to a hired photographer. It was fantastic, beyond words can explain the emotions flowing.&quot;</p><p>[Quelle von Bild und Text: coral11. -- <a href="http://www.flickr.com/photos/coral/36326932/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/coral/36326932/</a>. -- Zugriff am 2008-12-26. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p></blockquote><p>दा + आ 3Ā अदत्ते : (in Empfang) nehmen, in Besitz nehmen, mitnehmen</p><blockquote><p>Absol. आदाय : mit Akk.: in Begleitung von, mit</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: सा पुत्रमादाय भारं बिभर्ती गच्छति<br> Udaipur = उदयपुर<br> [Bildquelle: gscottie8. -- <a href="http://www.flickr.com/photos/gscottie/2152543713/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gscottie/2152543713/</a>. -- Zugriff am 2008-12-27. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>धा 3U दधाति : setzen, festsetzen, zuteilen</p><blockquote><p>Fut. धास्यति<br> Pass. धीयते<br> Kaus. धापयति<br> PPP हित (!!)<br> Inf. धातुम्</p></blockquote><p>धा + सम् + आ 3U समादधाति : die ganze Aufmerksamkeit auf etwas richten, sich sammeln</p><blockquote><p>davon:</p><p>समाधि m.: innere Sammlung, höchste Aufmerksamkeit</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: समाधि<br> योगिनी, Kaveripakkam = காவேரிப்பாக்கம், Tamil Nadu, 10. Jhdt. n. Chr.<br> [Bildquelle: Quadell / Wikipedia. GNU FDLicense]</p><p>पॄ 3P पिपर्ति :füllen erfüllen</p><blockquote><p>Merke:</p><p>3.pl.P पिपुरति<br> 3.sg.Impf.P अपिपर् (aus: *apipart)<br> 3.pl.Impf.P अपिपरुर्<br> 3.sg.Opt.P पिपूर्यात्</p><p>Fut. परिष्यति । परीष्यति<br> Pass. पूर्यते<br> Kaus. पूरयति । पारयति<br> PPP पूर्ण । पूर्त । पूरित</p></blockquote><p>पॄ + सम् nur Pass. सम्पूर्यते und Kaus.: gänzlich füllen</p><p>भी 3P बिभेति : sich fürchten vor (Abl., Gen.)</p><blockquote><p>Fut. भेष्यति<br> Pass. भीयते<br> Kaus. भाययति<br> PPP भीत<br> Inf. भेतुम्</p><p>davon.</p><p>भय n.: Angst Furcht ; Gefahr (also die subjektive und die objektive Seite)</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: भयम्<br> Mumbai = मुंबई, 2008<br> [Bildquelle: sameer5678in. -- <a href="http://www.flickr.com/photos/guptasameer/3080350405/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/guptasameer/3080350405/</a>. -- Zugriff am 2008-12-26. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>भृ 3U बिभर्ति : tragen, bringen ; erhalten, ernähren</p><blockquote><p>Fut. भरिष्यति<br> Pass. भ्रियते<br> Kaus. भारयति<br> PPP भृत<br> Inf. भर्तुम्</p><p>davon:</p><p>भार m.: Last</p></blockquote><p>मा 3Ā मिमीते : messen</p><blockquote><p>मास्यति । मास्यते<br> मीयते<br> मापयति<br> मित<br> मातुम्</p></blockquote><p>मा + उप 3Ā उपमिमीते : vergleichen</p><blockquote><p>davon:</p><p>उपमा f.: Vergleich</p><p>प्रतिमा f.: Abbild</p></blockquote><p>हा 3P जहाति : verlassen</p><blockquote><p>Fut. हास्यति<br> Pass. हीयते<br> Kaus. हापयति<br> PPP हीन : verlassen von, ermangelnd, mangelhaft<br> Inf. हातुम्</p><p>von PPP हीन :</p><p>हीनयान n.:  das mangelhafte Fahrzeug (des Budhismus): verächtliche Bezeichnung durch die Vertreter der &quot;großen Fahrzeugs&quot;, des महायान ; der mangelhafte Weg (यान zu या 2: gehen, fahren). Der Ausdruck हीनयान sollte nicht mehr verwendet werden. Die heute noch existierende Form des alten Buddhismus heißt थेरवाद.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: हीनयानमेव<br> Thailand<br> [Bildquelle: grrrrl. -- <a href="http://www.flickr.com/photos/11619899@N00/867938692/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/11619899@N00/867938692/</a>. -- Zugriff am 2008-12-26. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>हु 3P जुहोति : ins Feuer gießen (als Opfer, bes. Schmelzbutter)</p><blockquote><p>Fut. होष्यति<br> Pass. हूयते<br> Kaus. हावयति<br> PPP हुत<br> Inf. होतुम्</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: घृतमग्नौ जुहोति<br> यज्ञ im Shiva ashram, Kothavala, Ganeshpuri, 80 km von Mumbai (मुंबई) entfernt<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/466758922/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/466758922/</a>. -- Zugriff am 2008-12-26. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>घृत n.: Schmelzbutter, Ghee = घी / گھی  / ঘী</p><p>SAbb.: घृतम्<br> [Bildquelle: Wikipedia. GNU FDLicense]</p><blockquote><p>&quot;Ghee is made by simmering unsalted butter in a large pot until all water has boiled off and protein has settled to the bottom. The cooked and clarified butter is then spooned off to avoid disturbing the milk solids on the bottom of the pan. Unlike butter, ghee can be stored for extended periods without refrigeration, provided it is kept in an airtight container to prevent oxidation and remains moisture-free. Texture, colour, or taste of ghee depends on the source of the milk from which the butter was made. In India, ghee is usually made with water buffalo&#39;s milk as it tends to be whiter than cow&#39;s milk.&quot;</p><p>[Quelle: <a href="http://en.wikipedia.org/wiki/Ghee" target="_blank" rel="noreferrer">http://en.wikipedia.org/wiki/Ghee</a>. -- Zugriff am 2008-12-26]</p></blockquote><h2 id="_33-7-ubung" tabindex="-1">33.7. Übung <a class="header-anchor" href="#_33-7-ubung" aria-label="Permalink to &quot;33.7. Übung&quot;">​</a></h2><p>A) Setzen Sie in folgendem Satzmuster die entsprechenden Formen der Wörter in der Klammer ein:</p><p>रामस् ... (चतुर्थ्येकवचने बहुवचने च) ... अन्नं ददाति । (भिक्षु । अग्नि । शूद्रा । गुनवान्पुत्र । देवान्स्तुवन्कवि । ब्राह्मणी । महान्साधु । धेनु)</p><p>B) Setzen Sie die entsprechenden Formen der in Klammern angegebenen Verben im Indikativ Präsens, Imperfekt und Optativ ein:</p><p>ब्राह्मनो घृतमग्नौ ... (हु) ॥१॥</p><p>बुद्धगता भयान्न ... (भी) ॥२॥</p><p>सुगतः कुलम् ... (हा) ॥३॥</p><p>दुर्जना भिक्षुभ्यो ऽन्नं न ... (दा) ॥४॥</p><p>साधुः कृष्णे मतिम् ... (धा + सम् + आ) ॥५॥</p><p>ईश्वरो लोकान् ... जनास्तु न ... (मा) ॥६॥</p><p>दासा भारान् ... (भृ) ॥७॥</p><p>ब्राह्मणी पात्रं जलेन ... (पॄ) ॥८॥</p><p>C) Übersetzen Sie und wandeln Sie Singularsätze in Pluralsätze um und umgekehrt:</p><p>योगयुक्तो मतिं दुःखमक्षनयन्त्यां प्रज्ञायां समाधत्ते ॥१॥</p><p>यो भिक्षवे दानानि द्द्यात्सो ऽपि दानपुण्यमाददीत ॥२॥</p><p>ब्राह्मणा भारं न बिभ्रतीति ब्राह्मणदासो भारं गृहमबिभः ॥३॥</p><p><img src="'+p+'" alt=""><br> Abb.: पुरुषा भारं न बिभ्रतीति स्त्री भारं गृहमबिभः<br> Delhi = दहली / دہلی<br> [Bildquelle: Ondrej Jaura. -- <a href="http://www.flickr.com/photos/ondrejj/2073900069/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ondrejj/2073900069/</a>. -- Zugriff am 2008-12-27. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>क्षत्रियशूरः पुत्रमादाय योद्धुं कुलमजहात् । स युद्धे शत्रुहतत्वाच्छरीरं हीत्वा पनर्भवमैत् ॥४॥</p><p>देवदत्तमपि सुखं दुःखमोक्षेष्टिं न पिपर्ति । सेष्टिः प्रज्ञयैव सम्पूर्यते ॥५॥</p><p>यः साधुर्भूतेभ्यो ऽभयं ददाति तस्माद्भूतानि न बिभ्यति स च तेभ्यो न बिभेति ॥६॥</p><p>मितमतयो नरकभयात्स्वर्गलोभाच्च पुण्यं कुर्वन्ति पापं च जहति । अमितप्रज्ञाबुद्धा हि नरकेभ्यो न बिभीयुः स्वर्गांश्च न लुभ्येयुः । ते भयं च लोभं चारुन्धन् ॥७॥</p>',120)])])}const w=e(h,[["render",b]]);export{P as __pageData,w as default};
